const c=document.getElementById("themeBtn");c.addEventListener("click",()=>{const e=document.documentElement.dataset.theme==="dark"?"light":"dark";document.documentElement.dataset.theme=e;try{localStorage.setItem("mc-theme",e)}catch{}});const n=document.getElementById("burger"),r=document.getElementById("drawer");n.addEventListener("click",()=>{const e=r.classList.toggle("open");n.setAttribute("aria-expanded",String(e))});r.querySelectorAll("a").forEach(e=>e.addEventListener("click",()=>{r.classList.remove("open"),n.setAttribute("aria-expanded","false")}));const o=document.getElementById("nav");window.addEventListener("scroll",()=>o.classList.toggle("scrolled",window.scrollY>10),{passive:!0});const s=new IntersectionObserver(e=>{e.forEach(t=>{t.isIntersecting&&(t.target.classList.add("in"),s.unobserve(t.target))})},{threshold:.07});document.querySelectorAll(".reveal").forEach(e=>s.observe(e));
